import{c as a,Q as r,j as o,m as t}from"./chunks/framework.BXc4yaFE.js";const f=JSON.parse('{"title":"The Decoder — 2026-05-09","description":"","frontmatter":{"title":"The Decoder — 2026-05-09","date":"2026-05-09T00:00:00.000Z","source":"The Decoder","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-09-the-decoder.md","filePath":"research/ai-news/2026-05/2026-05-09-the-decoder.md","lastUpdated":1779894392000}'),n={name:"research/ai-news/2026-05/2026-05-09-the-decoder.md"};function s(i,e,l,d,p,h){return r(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="🔓-the-decoder-—-2026-05-09" tabindex="-1">🔓 The Decoder — 2026-05-09 <a class="header-anchor" href="#🔓-the-decoder-—-2026-05-09" aria-label="Permalink to &quot;🔓 The Decoder — 2026-05-09&quot;">​</a></h1><blockquote><p>企業 AI 開發與模型應用日報，涵蓋 AI 社會影響（英語媒體） 來源：<a href="https://the-decoder.com/feed/" target="_blank" rel="noreferrer">The Decoder</a></p></blockquote><hr><h2 id="ai-money-keeps-flowing-as-deepseek-plans-record-raise-and-core-automation-quadruples-valuation-in-weeks" tabindex="-1"><a href="https://the-decoder.com/ai-money-keeps-flowing-as-deepseek-plans-record-raise-and-core-automation-quadruples-valuation-in-weeks/" target="_blank" rel="noreferrer">AI money keeps flowing as Deepseek plans record raise and Core Automation quadruples valuation in weeks</a> <a class="header-anchor" href="#ai-money-keeps-flowing-as-deepseek-plans-record-raise-and-core-automation-quadruples-valuation-in-weeks" aria-label="Permalink to &quot;[AI money keeps flowing as Deepseek plans record raise and Core Automation quadruples valuation in weeks](https://the-decoder.com/ai-money-keeps-flowing-as-deepseek-plans-record-raise-and-core-automation-quadruples-valuation-in-weeks/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-08</em></p><p>Deepseek is planning a funding round of up to $7.35 billion, the largest ever for a Chinese AI company. Deepseek V4.1 is set to launch in June. Meanwhile, Core Automation, founded by ex-OpenAI researcher Jerry Tworek just six weeks ago, is already targeting a $4 billion valuation.</p><p>The article <a href="https://the-decoder.com/ai-money-keeps-flowing-as-deepseek-plans-record-raise-and-core-automation-quadruples-valuation-in-weeks/" target="_blank" rel="noreferrer">AI money keeps flowing as Deepseek plans record raise and Core Automation quadruples valuation in weeks</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="softbank-reportedly-slashes-openai-backed-loan-from-10-billion-to-6-billion-as-lenders-balk-at-private-ai-valuations" tabindex="-1"><a href="https://the-decoder.com/softbank-reportedly-slashes-openai-backed-loan-from-10-billion-to-6-billion-as-lenders-balk-at-private-ai-valuations/" target="_blank" rel="noreferrer">SoftBank reportedly slashes OpenAI-backed loan from $10 billion to $6 billion as lenders balk at private AI valuations</a> <a class="header-anchor" href="#softbank-reportedly-slashes-openai-backed-loan-from-10-billion-to-6-billion-as-lenders-balk-at-private-ai-valuations" aria-label="Permalink to &quot;[SoftBank reportedly slashes OpenAI-backed loan from $10 billion to $6 billion as lenders balk at private AI valuations](https://the-decoder.com/softbank-reportedly-slashes-openai-backed-loan-from-10-billion-to-6-billion-as-lenders-balk-at-private-ai-valuations/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-08</em></p><p>SoftBank has reduced a loan secured by OpenAI shares from 10 to around 6 billion dollars. Lenders are apparently reluctant to reliably assess the value of an unlisted company like OpenAI.</p><p>The article <a href="https://the-decoder.com/softbank-reportedly-slashes-openai-backed-loan-from-10-billion-to-6-billion-as-lenders-balk-at-private-ai-valuations/" target="_blank" rel="noreferrer">SoftBank reportedly slashes OpenAI-backed loan from $10 billion to $6 billion as lenders balk at private AI valuations</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="anthropic-approaches-1-trillion-valuation-as-revenue-grows-fivefold" tabindex="-1"><a href="https://the-decoder.com/anthropic-approaches-1-trillion-valuation-as-revenue-grows-fivefold/" target="_blank" rel="noreferrer">Anthropic approaches $1 trillion valuation as revenue grows fivefold</a> <a class="header-anchor" href="#anthropic-approaches-1-trillion-valuation-as-revenue-grows-fivefold" aria-label="Permalink to &quot;[Anthropic approaches $1 trillion valuation as revenue grows fivefold](https://the-decoder.com/anthropic-approaches-1-trillion-valuation-as-revenue-grows-fivefold/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-08</em></p><p>According to the Financial Times, Anthropic&#39;s planned funding round is taking shape. The round aims to raise up to $50 billion, which would value the company at roughly $900 billion.</p><p>The article <a href="https://the-decoder.com/anthropic-approaches-1-trillion-valuation-as-revenue-grows-fivefold/" target="_blank" rel="noreferrer">Anthropic approaches $1 trillion valuation as revenue grows fivefold</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="ai-safety-tests-have-a-new-problem-models-are-now-faking-their-own-reasoning-traces" tabindex="-1"><a href="https://the-decoder.com/ai-safety-tests-have-a-new-problem-models-are-now-faking-their-own-reasoning-traces/" target="_blank" rel="noreferrer">AI safety tests have a new problem: Models are now faking their own reasoning traces</a> <a class="header-anchor" href="#ai-safety-tests-have-a-new-problem-models-are-now-faking-their-own-reasoning-traces" aria-label="Permalink to &quot;[AI safety tests have a new problem: Models are now faking their own reasoning traces](https://the-decoder.com/ai-safety-tests-have-a-new-problem-models-are-now-faking-their-own-reasoning-traces/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-08</em></p><p>Anthropic&#39;s Natural Language Autoencoders make Claude Opus 4.6&#39;s internal activations readable as plain text. Pre-deployment audits show that models often recognize test situations and deliberately deceive evaluators - without revealing any of this in their visible reasoning traces. The method confirms a growing safety problem and offers a possible way to address it.</p><p>The article <a href="https://the-decoder.com/ai-safety-tests-have-a-new-problem-models-are-now-faking-their-own-reasoning-traces/" target="_blank" rel="noreferrer">AI safety tests have a new problem: Models are now faking their own reasoning traces</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="openai-opens-gpt-5-5-cyber-to-vetted-security-researchers" tabindex="-1"><a href="https://the-decoder.com/openai-opens-gpt-5-5-cyber-to-vetted-security-researchers/" target="_blank" rel="noreferrer">OpenAI opens GPT-5.5-Cyber to vetted security researchers</a> <a class="header-anchor" href="#openai-opens-gpt-5-5-cyber-to-vetted-security-researchers" aria-label="Permalink to &quot;[OpenAI opens GPT-5.5-Cyber to vetted security researchers](https://the-decoder.com/openai-opens-gpt-5-5-cyber-to-vetted-security-researchers/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-08</em></p><p>OpenAI is releasing GPT-5.5-Cyber, a model variant that rejects far fewer security requests and even actively executes exploits against test servers. Access is limited to verified defenders of critical infrastructure, including partners like Cisco, CrowdStrike, and Cloudflare. The model competes directly with Anthropic&#39;s Mythos Preview.</p><p>The article <a href="https://the-decoder.com/openai-opens-gpt-5-5-cyber-to-vetted-security-researchers/" target="_blank" rel="noreferrer">OpenAI opens GPT-5.5-Cyber to vetted security researchers</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr>',28)])])}const u=a(n,[["render",s]]);export{f as __pageData,u as default};
